import{_ as i,r as t,o,c as l,b as e,d as n,a as d,e as s}from"./app.0a43b3c6.js";const c={},r=d(`<h1 id="an-introduction-to-the-npm-package-manager" tabindex="-1"><a class="header-anchor" href="#an-introduction-to-the-npm-package-manager" aria-hidden="true">#</a> An introduction to the NPM package manager</h1><h2 id="introduction-to-npm" tabindex="-1"><a class="header-anchor" href="#introduction-to-npm" aria-hidden="true">#</a> Introduction to npm</h2><ul><li>npm is the standard package manager for Node.js.</li><li>It started as a way to download and manage dependencies of Node.js packages, but it has since become a tool used also in frontend JavaScript.</li></ul><h2 id="packages" tabindex="-1"><a class="header-anchor" href="#packages" aria-hidden="true">#</a> Packages</h2><ul><li>npm manages downloads of dependencies of your project.</li></ul><h3 id="installing-all-dependencies" tabindex="-1"><a class="header-anchor" href="#installing-all-dependencies" aria-hidden="true">#</a> Installing all dependencies</h3><ul><li>If a project has a package.json file, by running <code>npm install</code>, it will install everything the project needs.</li></ul><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span>
</code></pre></div><h3 id="installing-a-single-package" tabindex="-1"><a class="header-anchor" href="#installing-a-single-package" aria-hidden="true">#</a> Installing a single package</h3><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span> <span class="token variable"><span class="token variable">\`</span><span class="token operator">&lt;</span>package-name<span class="token operator">&gt;</span><span class="token variable">\`</span></span>
</code></pre></div><ul><li><p>Furthermore, since npm 5, this command adds <code>&lt;package-name&gt;</code> to the <code>package.json</code> file dependencies. Before version 5, you needed to add the flag <code>--save</code>.</p></li><li><p>More flags:</p><ul><li><code>--save-dev</code> installs and adds the entry to the package.json file <em>devDependencies</em></li><li><code>--no-save</code> installs but does not add the entry to the package.json file <em>dependencies</em></li><li><code>--save-optional</code> installs and adds the entry to the package.json file <em>optionalDependencies</em></li><li><code>--no-optional</code> will prevent optional dependencies from being installed</li></ul></li><li><p>Shorthands:</p><ul><li><code>-S</code>: --save</li><li><code>-D</code>: --save-dev</li><li><code>-O</code>: --save-optional</li></ul></li><li><p>The difference between <em>devDependencies</em> and <em>dependencies</em> is that the former contains development tools, like a testing library, while the latter is bundled with the app in production.</p></li><li><p>As for the optionalDependencies the difference is that build failure of the dependency will not cause installation to fail.</p></li></ul><h3 id="updating-packages" tabindex="-1"><a class="header-anchor" href="#updating-packages" aria-hidden="true">#</a> Updating packages</h3><ul><li><code>npm update</code> will check all packages for a newer version that satisfies your versioning constraints.</li><li><code>npm update &lt;package-name&gt;</code> will update a single package.</li></ul><h2 id="versioning" tabindex="-1"><a class="header-anchor" href="#versioning" aria-hidden="true">#</a> Versioning</h2><ul><li>In addition to plain downloads, npm also manages versioning, so you can specify any specific version of a package.</li><li>Many times you&#39;ll find that a library is only compatible with a major release of another library, or a bug in the latest release of a lib, still unfixed, is causing an issue.</li></ul><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span> <span class="token operator">&lt;</span>package-name<span class="token operator">&gt;</span>@<span class="token operator">&lt;</span>version<span class="token operator">&gt;</span>
</code></pre></div><h2 id="running-tasks" tabindex="-1"><a class="header-anchor" href="#running-tasks" aria-hidden="true">#</a> Running Tasks</h2><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">npm</span> run dev
</code></pre></div><h2 id="refs" tabindex="-1"><a class="header-anchor" href="#refs" aria-hidden="true">#</a> Refs</h2>`,19),p={href:"https://nodejs.dev/en/learn/an-introduction-to-the-npm-package-manager/",target:"_blank",rel:"noopener noreferrer"},h=s("An introduction to the NPM package manager"),g={href:"https://docs.npmjs.com/",target:"_blank",rel:"noopener noreferrer"},u=s("NPM documents"),m={href:"https://docs.npmjs.com/cli/v7/configuring-npm/package-json#optionaldependencies",target:"_blank",rel:"noopener noreferrer"},f=s("optionalDependencies");function k(_,v){const a=t("ExternalLinkIcon");return o(),l("div",null,[r,e("ul",null,[e("li",null,[e("a",p,[h,n(a)])]),e("li",null,[e("a",g,[u,n(a)])]),e("li",null,[e("a",m,[f,n(a)])])])])}const x=i(c,[["render",k],["__file","05_an_introduction_to_the_npm_package_manager.html.vue"]]);export{x as default};
